/* BTDropdownList — Figma node 668-8852
 *
 * Shared by Vue (imported here) and React (imported in BTDropdownList.tsx).
 * All var() names verified against packages/tokens/platforms/web/bspace/dist/styles.css.
 * No hex fallback per CLAUDE.md §6.
 */

/* ── Container ──────────────────────────────────────────────────────────────── */

.bt-dropdown-list {
  background: var(--bg-primary);
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-sm);
  box-shadow: var(--shadow-elevation-md);
  /* Fill whatever container places this list (BTInputDropdown panel, BTInputDate
   * panel, etc.). The parent is responsible for setting its own width. */
  width: 100%;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  box-sizing: border-box;
  max-height: 240px;
}

/* ── Items scroll wrapper ───────────────────────────────────────────────────── */

.bt-dropdown-list__items {
  flex: 1;
  min-height: 0;
  display: flex;
  flex-direction: column;
}

.bt-dropdown-list__items .bt-scrollbar {
  flex: 1;
  min-height: 0;
}

/* ── Search section ─────────────────────────────────────────────────────────── */

.bt-dropdown-list__search {
  padding: var(--space-sm) var(--space-md);
  flex-shrink: 0;
}

/* ── List items ─────────────────────────────────────────────────────────────── */

.bt-dropdown-list__item {
  display: flex;
  align-items: center;
  gap: var(--space-xs);
  min-height: 32px;   /* Figma node 668-8852 — each item hugs to 32px */
  padding: var(--space-sm);
  width: 100%;
  box-sizing: border-box;
  cursor: pointer;
  transition: background 100ms ease;
}

.bt-dropdown-list__item:hover:not(.bt-dropdown-list__item--disabled) {
  background: var(--bg-subtle);
}

.bt-dropdown-list__item:active:not(.bt-dropdown-list__item--disabled) {
  background: var(--bg-secondary);
}

.bt-dropdown-list__item--disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

/* Checked row — applies to any variant where the caller stamps item.checked — brand-primary-subtle background.
 * var(--color-brand-primary-subtle) verified in packages/tokens/platforms/web/bspace/dist/styles.css */
.bt-dropdown-list__item--checked {
  background: var(--color-brand-primary-subtle);
}

.bt-dropdown-list__item--checked:hover:not(.bt-dropdown-list__item--disabled) {
  background: var(--color-brand-primary-subtle);
}

/* Selectable items (checkbox + radio) — same 32px hugging height, 8px gap between control + label */
.bt-dropdown-list__item--selectable {
  height: auto;
  gap: var(--space-sm);
  padding: var(--space-sm);
  align-items: center;
}

/* Suppress internal pointer events on embedded controls — the row handles taps */
.bt-dropdown-list__checkbox,
.bt-dropdown-list__radio-control {
  pointer-events: none;
  flex-shrink: 0;
}

/* Combobox items have a wider gap and no fixed height (avatar sizes them) */
.bt-dropdown-list__item--combobox {
  gap: var(--space-sm);
  height: auto;
  padding: var(--space-xs) var(--space-sm);
}

.bt-dropdown-list__item-label {
  font-size: var(--typography-font-size-sm);   /* 14px */
  font-weight: 500;
  color: var(--text-primary);
  line-height: var(--typography-line-height-xs);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  flex: 1;
  min-width: 0;
}

/* Remove (×) affordance on the right of a removable row */
.bt-dropdown-list__item-remove {
  flex-shrink: 0;
  width: 16px;
  height: 16px;
  color: var(--icon-secondary);
  display: inline-block;
  pointer-events: none; /* row click handles the action */
}

/* ── Avatar (combobox only) ─────────────────────────────────────────────────── */

.bt-dropdown-list__avatar {
  width: 24px;
  height: 24px;
  border-radius: var(--radius-rd);
  flex-shrink: 0;
  overflow: hidden;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: var(--typography-font-size-2xs);  /* 10px */
  font-weight: 500;
  color: var(--text-inverse);
}

/* ── Empty / not-found state ────────────────────────────────────────────────── */

.bt-dropdown-list__empty {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 24px;
  gap: 0;
  width: 100%;
  box-sizing: border-box;
}

.bt-dropdown-list__empty-image {
  width: 80px;
  height: auto;
  display: block;
}

.bt-dropdown-list__empty-text {
  font-size: 11px;                             /* component-specific — no token match */
  font-weight: 500;
  color: #7e93a8;                              /* component-specific palette — hardcoded per CLAUDE.md §2 */
  text-align: center;
  line-height: var(--typography-line-height-xs);
  margin-top: var(--space-xs);
}

/**
 * BTDropdownList — floating option list atom.
 * Figma source: node 668-8852.
 *
 * Purely presentational — caller handles positioning, filtering, and
 * visibility toggling.
 *
 * @example
 * // List variant
 * <BTDropdownList
 *   items={[{ value: 'a', label: 'Option A' }, { value: 'b', label: 'Option B' }]}
 *   onSelect={handleSelect}
 * />
 *
 * @example
 * // Combobox variant with search
 * <BTDropdownList
 *   variant="combobox"
 *   searchable
 *   searchQuery={query}
 *   onSearchChange={setQuery}
 *   items={filteredUsers}
 *   onSelect={handleSelectUser}
 * />
 *
 * @example
 * // Checkbox multi-select
 * <BTDropdownList
 *   variant="checkbox"
 *   items={items}
 *   onSelect={handleToggle}
 * />
 */
import './BTDropdownList.css';
import type { BTDropdownListProps, BTDropdownItem } from './BTDropdownList.types';
import { BTCheckbox } from '../checkbox/BTCheckbox';
import { BTRadioButton } from '../radio-button/BTRadioButton';
import { BTScrollbar } from '../scrollbar/BTScrollbar';
import { BTInputSearch } from '../input-search/BTInputSearch';
import emptyStateImg from './illus/empty-state.svg';

// Avatar color map — mirrors BTAvatar component-specific palette
const AVATAR_COLORS: Record<string, string> = {
  green: '#89ae68',
  blue: '#93c6ef',
  orange: '#f0a070',
  purple: '#b39ddb',
  teal: '#80cbc4',
  pink: '#f48fb1',
};

function deriveInitials(name: string): string {
  const trimmed = (name ?? '').trim();
  if (!trimmed) return '?';
  const words = trimmed.split(/\s+/);
  if (words.length === 1) return words[0]!.charAt(0).toUpperCase();
  return (words[0]!.charAt(0) + words[words.length - 1]!.charAt(0)).toUpperCase();
}

export function BTDropdownList<T = string>({
  variant = 'list',
  items,
  searchable = false,
  searchQuery = '',
  onSearchChange,
  onSelect,
  emptyLabel = 'No result found.',
  className,
}: BTDropdownListProps<T>) {
  const isEmpty = items.length === 0;
  const isCombobox = variant === 'combobox';
  const isCheckbox = variant === 'checkbox';
  const isRadio = variant === 'radio';

  function renderItem(item: BTDropdownItem<T>) {
    const avatarBg = AVATAR_COLORS[item.avatar?.color ?? 'green'] ?? '#89ae68';
    const isChecked = item.checked ?? false;

    const itemClass = [
      'bt-dropdown-list__item',
      isCombobox ? 'bt-dropdown-list__item--combobox' : '',
      isCheckbox || isRadio ? 'bt-dropdown-list__item--selectable' : '',
      item.disabled ? 'bt-dropdown-list__item--disabled' : '',
      isChecked ? 'bt-dropdown-list__item--checked' : '',
    ]
      .filter(Boolean)
      .join(' ');

    return (
      <div
        key={item.value !== undefined ? String(item.value) : item.label}
        className={itemClass}
        role="option"
        aria-selected={isChecked}
        aria-disabled={item.disabled}
        onClick={() => !item.disabled && item.value !== undefined && onSelect?.(item.value)}
      >
        {/* Checkbox control — className applied directly (matches Vue structure, no wrapper span) */}
        {isCheckbox && (
          <BTCheckbox
            checked={isChecked}
            disabled={item.disabled}
            onChange={() => {/* row handles click */}}
            className="bt-dropdown-list__checkbox"
          />
        )}

        {/* Radio control — className applied directly so BTRadioButton IS the flex item
             (mirrors Flutter's IgnorePointer > BTRadioButton, no wrapper widget).
             bt-dropdown-list__radio-control merges onto the root label via className prop. */}
        {isRadio && (
          <BTRadioButton
            className="bt-dropdown-list__radio-control"
            modelValue={item.checked ?? false}
            value={true}
            onChange={() => {/* row handles click */}}
            disabled={item.disabled}
          />
        )}

        {/* Avatar (combobox only) */}
        {isCombobox && item.avatar && (
          <div
            className="bt-dropdown-list__avatar"
            style={item.avatar.imageUrl ? undefined : { background: avatarBg }}
            aria-hidden="true"
          >
            {item.avatar.imageUrl ? (
              <img
                src={item.avatar.imageUrl}
                alt={item.avatar.name}
                style={{ width: '100%', height: '100%', objectFit: 'cover', borderRadius: 'inherit' }}
              />
            ) : (
              <span>{deriveInitials(item.avatar.name)}</span>
            )}
          </div>
        )}

        <span className="bt-dropdown-list__item-label">{item.label}</span>

        {/* Remove (×) affordance — space-between with label.
            Same path as BTTag __close (filled-circle ×, single fill). */}
        {item.removable && (
          <svg
            className="bt-dropdown-list__item-remove"
            width="16"
            height="16"
            viewBox="0 0 16 16"
            fill="none"
            aria-hidden="true"
          >
            <path d="M8 1.5C4.41 1.5 1.5 4.41 1.5 8C1.5 11.59 4.41 14.5 8 14.5C11.59 14.5 14.5 11.59 14.5 8C14.5 4.41 11.59 1.5 8 1.5ZM11 10.29L10.29 11L8 8.71L5.71 11L5 10.29L7.29 8L5 5.71L5.71 5L8 7.29L10.29 5L11 5.71L8.71 8L11 10.29Z" fill="currentColor"/>
          </svg>
        )}
      </div>
    );
  }

  return (
    <div className={['bt-dropdown-list', className].filter(Boolean).join(' ')} role="listbox">
      {/* Search bar */}
      {searchable && (
        <div className="bt-dropdown-list__search">
          <BTInputSearch
            value={searchQuery}
            placeholder="Search"
            onChange={(v) => onSearchChange?.(v)}
          />
        </div>
      )}

      {/* Items / empty state — scrollable when content exceeds 240px */}
      <div className="bt-dropdown-list__items">
      <BTScrollbar direction="y">
        {!isEmpty
          ? items.map((item) => renderItem(item))
          : (
            <div className="bt-dropdown-list__empty" role="status" aria-live="polite">
              <img src={emptyStateImg} alt="" className="bt-dropdown-list__empty-image" />
              <span className="bt-dropdown-list__empty-text">{emptyLabel}</span>
            </div>
          )}
      </BTScrollbar>
      </div>
    </div>
  );
}

BTDropdownList.displayName = 'BTDropdownList';

/**
 * BTDropdownList — public API types (React).
 * Mirror of packages/ui/vue/…/BTDropdownList.types.ts — keep in sync.
 */
import type { BTAvatarItem } from '../avatar/BTAvatar.types';

export type BTDropdownListVariant = 'list' | 'combobox' | 'checkbox' | 'radio';

/**
 * A single row item in BTDropdownList.
 *
 * Generic over T so callers can use any value type (string, number, etc.).
 * Default is `string` for backwards compatibility.
 */
export interface BTDropdownItem<T = string> {
  value?: T;
  label?: string;
  disabled?: boolean;
  /**
   * Whether this item is checked — used in `checkbox` and `radio` variants
   * to render the control as selected and apply the checked-row background.
   */
  checked?: boolean;
  avatar?: BTAvatarItem;
  /**
   * When true, renders a × icon on the right (space-between layout). Signals
   * that tapping the row performs a destructive action (e.g. remove filter).
   */
  removable?: boolean;
}

/**
 * @deprecated Use BTDropdownItem instead. Will be removed in the next major.
 */
export type BTDropdownListItem<T = string> = BTDropdownItem<T>;

export interface BTDropdownListProps<T = string> {
  /** @default 'list' */
  variant?: BTDropdownListVariant;
  items: BTDropdownItem<T>[];
  /** @default false */
  searchable?: boolean;
  searchQuery?: string;
  onSearchChange?: (query: string) => void;
  onSelect?: (value: T) => void;
  /** @default 'No result found.' */
  emptyLabel?: string;
  className?: string;
}

export { BTDropdownList } from './BTDropdownList';
export type {
  BTDropdownListVariant,
  BTDropdownItem,
  BTDropdownListItem,
  BTDropdownListProps,
} from './BTDropdownList.types';
